code_changes.content:
[
  {
    "file": "lib/vtls/openssl.c",
    "line": 1129,
    "severity": "high",
    "description": "SSL_CTX_use_certificate_blob returns CURLE_OUT_OF_MEMORY (a CURLcode value) instead of 0 (SSL error code). The function return type is int which should be 0 for error or the result of SSL_CTX_use_certificate. Returning a non-zero CURLcode value will be misinterpreted as success (SSL functions return 1 for success, 0 for error). This causes memory allocation failures to be silently ignored.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -1127,7 +1127,7 @@ SSL_CTX_use_certificate_blob(SSL_CTX *ctx, const struct curl_blob *blob,
    /* the typecast of blob->len is fine since it is guaranteed to never be
       larger than CURL_MAX_INPUT_LENGTH */
    BIO *in = BIO_new_mem_buf(blob->data, (int)(blob->len));
    if(!in)
-    return CURLE_OUT_OF_MEMORY;
+    return 0;
"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 1165,
    "severity": "high",
    "description": "SSL_CTX_use_PrivateKey_blob returns CURLE_OUT_OF_MEMORY instead of 0 on memory allocation failure. This function returns int (SSL error codes where 0=error, 1=success) but returns a CURLcode value. This causes the error to be misinterpreted and memory allocation failures are silently ignored, potentially leading to use of uninitialized SSL contexts.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -1163,7 +1163,7 @@ SSL_CTX_use_PrivateKey_blob(SSL_CTX *ctx, const struct curl_blob *blob,
    int ret = 0;
    EVP_PKEY *pkey = NULL;
    BIO *in = BIO_new_mem_buf(blob->data, (int)(blob->len));
    if(!in)
-    return CURLE_OUT_OF_MEMORY;
+    return 0;
"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 2180,
    "severity": "critical",
    "description": "X509_get_ext_d2i is called with NULL pointers for the 3rd and 4th parameters, preventing error status checking. When called with NULL pointers, the function cannot distinguish between "extension not found" (normal) and "extension exists but is malformed/critical and cannot be parsed" (error). This is a certificate verification bypass vulnerability: if the SAN extension exists but cannot be parsed, the code silently skips SAN verification and falls back to Common Name verification, allowing attackers to impersonate valid certificate holders.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -2178,7 +2178,10 @@ ossl_verifyhost(struct Curl_easy *data, struct connectdata *conn,
 }

   /* get a "list" of alternative names */
-  altnames = X509_get_ext_d2i(server_cert, NID_subject_alt_name, NULL, NULL);
+  int critical = -1;
+  altnames = X509_get_ext_d2i(server_cert, NID_subject_alt_name, &critical,
+                              NULL);
+  if(critical != 0 && critical != -1) {
+    failf(data, "SSL: error parsing Subject Alternative Name");
+    return CURLE_PEER_FAILED_VERIFICATION;
+  }
"
  },
  {
    "file": "lib/base64.c",
    "line": 120,
    "severity": "high",
    "description": "The lookup table initialization is incomplete. The memcpy from decodetable to lookup starting at offset 43 only covers ASCII characters 43-106, but valid base64 characters extend to 'z' (ASCII 122). This means characters 'k' through 'z' (positions 36-51 in the base64 alphabet) will not decode correctly and will be rejected as invalid. This breaks base64 decoding for approximately half of the standard base64 alphabet.",
    "fix_patch": "--- a/lib/base64.c
+++ b/lib/base64.c
@@ -117,9 +117,12 @@ CURLcode Curl_base64_decode(const char *src,
    pos = newstr;

    memset(lookup, 0xff, sizeof(lookup));
-  memcpy(&lookup['+'], decodetable, sizeof(decodetable));
-  /* replaces
-  {
+  /* Build lookup table from base64 alphabet */
+  {
     unsigned char c;
     const unsigned char *p = (const unsigned char *)base64encdec;
     for(c = 0; *p; c++, p++)
       lookup[*p] = c;
-  }
-  */
"
  }
]

code_changes.new_string:
  {
    "file": "lib/vtls/openssl.c",
    "line": 2180,
    "severity": "critical",
    "description": "X509_get_ext_d2i is called with NULL pointers for the 3rd and 4th parameters, preventing error status checking. When called with NULL pointers, the function cannot distinguish between "extension not found" (normal) and "extension exists but is malformed/critical and cannot be parsed" (error). This is a certificate verification bypass vulnerability: if the SAN extension exists but cannot be parsed, the code silently skips SAN verification and falls back to Common Name verification, allowing attackers to impersonate valid certificate holders.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -2154,6 +2154,7 @@ ossl_verifyhost(struct Curl_easy *data, struct connectdata *conn,
    size_t hostlen;

    (void)conn;
+  int critical = -1;
    hostlen = strlen(hostname);

@@ -2178,8 +2179,15 @@ ossl_verifyhost(struct Curl_easy *data, struct connectdata *conn,
    }

    /* get a "list" of alternative names */
-   altnames = X509_get_ext_d2i(server_cert, NID_subject_alt_name, NULL, NULL);
+   altnames = X509_get_ext_d2i(server_cert, NID_subject_alt_name, &critical, NULL);
+
+   /* Check if the extension exists but is critical and unparseable */
+   if(altnames == NULL && critical > 0) {
+     failf(data, "SSL: error parsing Subject Alternative Name");
+     result = CURLE_PEER_FAILED_VERIFICATION;
+     goto cleanup;
+   }

    if(altnames) {
"
  }

